import React, { useState, useEffect, useRef } from "react";
import api from "../api/axiosInstance";
import { getSensorByUser } from "../api/sensorsapi";

// ─── KPI API calls ──────────────────────────────────────────────────────────
const createKPI = (payload) =>
  api.post("/api/KPIs", {
    KPIName: payload.name,
    KPIFormula: payload.formula,
    Frequency: payload.frequency || "5min",
  });

const fetchKPIs = () => api.get(`/api/KPIs`);

// NEW: fetch latest value for a single KPI
const fetchKPILatest = (kpiId) =>
  api.get(`/api/KPIs/${kpiId}/latest`);

// ─── Formula evaluator ──────────────────────────────────────────────────────


// ─── Trend data generator ───────────────────────────────────────────────────
const genTrendData = (baseVal, range) => {
  const counts = { "1h": 12, "6h": 24, "24h": 24, "7d": 7, "30d": 30 };
  const n = counts[range] || 24;
  const b = parseFloat(baseVal) || 50;
  return Array.from({ length: n }, () => +(b + (Math.random() - 0.5) * b * 0.15).toFixed(2));
};

const getTrendLabels = (range) => {
  const cfg = {
    "1h":  { n: 12, fn: (i, n) => `-${(n - i) * 5}m` },
    "6h":  { n: 24, fn: (i, n) => `-${(n - i) * 15}m` },
    "24h": { n: 24, fn: (i, n) => `-${n - i}h` },
    "7d":  { n: 7,  fn: (i) => ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"][i] },
    "30d": { n: 30, fn: (i) => `Day ${i + 1}` },
  };
  const { n, fn } = cfg[range] || cfg["24h"];
  return Array.from({ length: n }, (_, i) => fn(i, n));
};

// ─── Constants ──────────────────────────────────────────────────────────────
const ICON_MAP = {
  availability: "bi-check2-circle",
  performance:  "bi-speedometer2",
  quality:      "bi-award",
  oee:          "bi-graph-up",
  downtime:     "bi-clock-history",
};
const COLOR_MAP  = ["#00c6ae","#0f8fd4","#7b5ea7","#f39c12","#e74c3c","#2ecc71","#e91e63"];
const OPERATORS  = [
  { label: "+", val: " + " }, { label: "−", val: " - " },
  { label: "×", val: " * " }, { label: "÷", val: " / " },
  { label: "(", val: "("  }, { label: ")", val: ")"  },
];
const FX_FUNCS   = ["SUM", "AVG", "MAX", "MIN"];
const FREQUENCIES = ["1min","5min","15min","30min","1hr","6hr","12hr","24hr"];
const TREND_RANGES = ["1h","6h","24h","7d","30d"];

// ─── Chart with X & Y Axis ──────────────────────────────────────────────────
const TrendChart = ({ data, color, labels }) => {
  const ref = useRef(null);

  useEffect(() => {
    const canvas = ref.current;
    if (!canvas || !data.length) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width;
    const H = canvas.height;

    const PAD_LEFT   = 42;
    const PAD_RIGHT  = 10;
    const PAD_TOP    = 12;
    const PAD_BOTTOM = 28;

    const plotW = W - PAD_LEFT - PAD_RIGHT;
    const plotH = H - PAD_TOP  - PAD_BOTTOM;

    const min   = Math.min(...data);
    const max   = Math.max(...data);
    const range = max - min || 1;

    ctx.clearRect(0, 0, W, H);

    // ── Grid lines & Y-axis labels ──
    const yTicks = 4;
    ctx.strokeStyle = "rgba(150,150,150,0.15)";
    ctx.lineWidth   = 1;
    ctx.font        = "9px monospace";
    ctx.fillStyle   = "rgba(150,150,150,0.8)";
    ctx.textAlign   = "right";

    for (let i = 0; i <= yTicks; i++) {
      const val = min + (range * i) / yTicks;
      const y   = PAD_TOP + plotH - (plotH * i) / yTicks;
      ctx.beginPath();
      ctx.moveTo(PAD_LEFT, y);
      ctx.lineTo(PAD_LEFT + plotW, y);
      ctx.stroke();
      ctx.fillText(val.toFixed(1), PAD_LEFT - 4, y + 3);
    }

    // ── X-axis ticks ──
    const xTickCount = Math.min(5, data.length - 1);
    ctx.textAlign = "center";
    ctx.fillStyle = "rgba(150,150,150,0.8)";
    for (let i = 0; i <= xTickCount; i++) {
      const idx = Math.round((i / xTickCount) * (data.length - 1));
      const x   = PAD_LEFT + (idx / (data.length - 1)) * plotW;
      ctx.fillText(labels[idx] || "", x, H - 6);
      ctx.beginPath();
      ctx.strokeStyle = "rgba(150,150,150,0.25)";
      ctx.moveTo(x, PAD_TOP);
      ctx.lineTo(x, PAD_TOP + plotH);
      ctx.stroke();
    }

    // ── Axes ──
    ctx.strokeStyle = "rgba(150,150,150,0.35)";
    ctx.lineWidth   = 1;
    ctx.beginPath();
    ctx.moveTo(PAD_LEFT, PAD_TOP);
    ctx.lineTo(PAD_LEFT, PAD_TOP + plotH);
    ctx.lineTo(PAD_LEFT + plotW, PAD_TOP + plotH);
    ctx.stroke();

    // ── Line ──
    ctx.beginPath();
    data.forEach((v, i) => {
      const x = PAD_LEFT + (i / (data.length - 1)) * plotW;
      const y = PAD_TOP  + plotH - ((v - min) / range) * plotH;
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.strokeStyle = color;
    ctx.lineWidth   = 2;
    ctx.lineJoin    = "round";
    ctx.stroke();

    // ── Fill under line ──
    const lastX = PAD_LEFT + plotW;
    const baseY = PAD_TOP  + plotH;
    ctx.lineTo(lastX, baseY);
    ctx.lineTo(PAD_LEFT, baseY);
    ctx.closePath();
    ctx.fillStyle = color + "22";
    ctx.fill();

    // ── Dot on last point ──
    const lastV = data[data.length - 1];
    const dotX  = PAD_LEFT + plotW;
    const dotY  = PAD_TOP  + plotH - ((lastV - min) / range) * plotH;
    ctx.beginPath();
    ctx.arc(dotX, dotY, 3.5, 0, Math.PI * 2);
    ctx.fillStyle = color;
    ctx.fill();

  }, [data, color, labels]);

  return (
    <canvas
      ref={ref}
      width={460}
      height={180}
      style={{ display: "block", width: "100%", height: 180 }}
    />
  );
};

// ─── TrendPopup (centered modal overlay) ────────────────────────────────────
const TrendPopup = ({ kpi, onClose }) => {
  const [range, setRange] = useState("24h");
  const [data,  setData]  = useState([]);
  const baseVal = kpi._liveVal;

  useEffect(() => {
    setData(genTrendData(baseVal, range));
  }, [range, baseVal]);

  const labels = getTrendLabels(range);
  const min = data.length ? Math.min(...data).toFixed(2) : "—";
  const max = data.length ? Math.max(...data).toFixed(2) : "—";
  const avg = data.length ? (data.reduce((s, v) => s + v, 0) / data.length).toFixed(2) : "—";

  return (
    <div
      style={{
        position: "fixed", inset: 0, zIndex: 2000,
        background: "rgba(0,0,0,0.45)",
        display: "flex", alignItems: "center", justifyContent: "center",
        padding: 16,
      }}
      onClick={onClose}
    >
      <div
        style={{
          width: "100%", maxWidth: 520,
          background: "var(--sb-white)",
          border: "1px solid var(--sb-border)",
          borderRadius: 20,
          padding: 24,
          boxShadow: "0 24px 64px rgba(0,0,0,0.18)",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{
              width: 32, height: 32, borderRadius: 8,
              background: kpi.color + "22",
              display: "flex", alignItems: "center", justifyContent: "center",
            }}>
              <i className={`bi ${kpi.icon}`} style={{ color: kpi.color, fontSize: "1rem" }} />
            </div>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700, color: "var(--sb-text)" }}>{kpi.name}</div>
              <div style={{ fontSize: 11, color: "var(--sb-muted)" }}>Trend Analysis</div>
            </div>
          </div>
          <button
            onClick={onClose}
            style={{
              background: "var(--sb-light-bg)", border: "1px solid var(--sb-border)",
              borderRadius: 8, width: 30, height: 30,
              display: "flex", alignItems: "center", justifyContent: "center",
              cursor: "pointer", color: "var(--sb-muted)", fontSize: 16,
            }}
          >×</button>
        </div>

        {/* Current value */}
        <div style={{
          display: "flex", alignItems: "baseline", gap: 6,
          marginBottom: 14, padding: "10px 14px",
          background: kpi.color + "10", borderRadius: 10,
          border: `1px solid ${kpi.color}30`,
        }}>
          <span style={{ fontSize: 28, fontWeight: 800, color: kpi.color, lineHeight: 1 }}>{kpi._liveVal}</span>
          {kpi.unit && <span style={{ fontSize: 13, color: "var(--sb-muted)" }}>{kpi.unit}</span>}
          <span style={{ marginLeft: "auto", fontSize: 11, color: "var(--sb-muted)", fontFamily: "monospace" }}>
            fx: {kpi.formula}
          </span>
        </div>

        {/* Range filter */}
        <div style={{ display: "flex", gap: 6, marginBottom: 12 }}>
          {TREND_RANGES.map((r) => (
            <button
              key={r}
              onClick={() => setRange(r)}
              style={{
                flex: 1, fontSize: 11, padding: "5px 0", borderRadius: 8, fontWeight: 700,
                cursor: "pointer", border: "1px solid", transition: "all 0.15s",
                background: range === r ? kpi.color : "var(--sb-light-bg)",
                color: range === r ? "#fff" : "var(--sb-muted)",
                borderColor: range === r ? kpi.color : "var(--sb-border)",
              }}
            >{r}</button>
          ))}
        </div>

        {/* Chart with axes */}
        <div style={{
          borderRadius: 12, overflow: "hidden",
          background: "var(--sb-light-bg)",
          border: "1px solid var(--sb-border)",
          padding: "10px 8px 6px",
        }}>
          <TrendChart data={data} color={kpi.color} labels={labels} />
        </div>

        {/* Stats row */}
        <div style={{
          display: "flex", justifyContent: "space-between",
          marginTop: 12, padding: "10px 14px",
          background: "var(--sb-light-bg)", borderRadius: 10,
          border: "1px solid var(--sb-border)",
        }}>
          {[["Min", min, "var(--sb-text)"], ["Avg", avg, kpi.color], ["Max", max, "var(--sb-text)"]].map(([label, val, col]) => (
            <div key={label} style={{ textAlign: "center" }}>
              <div style={{ fontSize: 10, color: "var(--sb-muted)", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>{label}</div>
              <div style={{ fontSize: 16, fontWeight: 800, color: col, marginTop: 2 }}>{val}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// ─── KPI Card ────────────────────────────────────────────────────────────────
const KPICard = ({ kpi }) => {
  const [showTrend, setShowTrend] = useState(false);
  const val    = kpi._liveVal;
  const noData = val === null || val === undefined || !kpi.formula || !kpi.formula.trim();

  const errorMessage = !kpi.formula || !kpi.formula.trim()
    ? "No formula configured yet."
    : val === null
    ? "Unable to compute — verify formula or sensor connection."
    : null;

  return (
    <>
      <div
        style={{
          background: noData
            ? "linear-gradient(135deg, rgba(229,62,62,0.07), rgba(252,235,235,0.6))"
            : "var(--sb-card-bg)",
          borderRadius: 16,
          border: noData ? "1.5px solid #e53e3e" : "1px solid var(--sb-border)",
          padding: 20,
          position: "relative",
          overflow: "visible",
          transition: "transform 0.2s, box-shadow 0.2s",
        }}
        onMouseEnter={(e) => {
          if (!noData) {
            e.currentTarget.style.transform  = "translateY(-3px)";
            e.currentTarget.style.boxShadow  = "0 12px 32px rgba(0,0,0,0.08)";
          }
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.transform = "";
          e.currentTarget.style.boxShadow = "";
        }}
      >
        {/* Top accent bar */}
        <div style={{
          position: "absolute", top: 0, left: 0, right: 0, height: 3,
          background: noData ? "#e53e3e" : kpi.color,
          borderRadius: "16px 16px 0 0",
        }} />

        {/* Icon — click to open trend */}
        <div
          onClick={() => { if (!noData) setShowTrend(true); }}
          title={noData ? undefined : "Click for trend"}
          style={{
            position: "absolute", top: 16, right: 16,
            width: 38, height: 38, borderRadius: 10,
            background: noData ? "rgba(229,62,62,0.12)" : kpi.color + "18",
            display: "flex", alignItems: "center", justifyContent: "center",
            cursor: noData ? "default" : "pointer",
            transition: "background 0.15s",
            fontSize: "1.1rem",
          }}
        >
          <i className={`bi ${kpi.icon}`} style={{ color: noData ? "#e53e3e" : kpi.color }} />
        </div>

        <div style={{ paddingRight: 52 }}>
          {/* KPI name */}
          <p style={{
            fontSize: "0.75rem", fontWeight: 700, color: "var(--sb-muted)",
            marginBottom: 6, textTransform: "uppercase", letterSpacing: "0.5px",
          }}>
            {kpi.name}
          </p>

          {noData ? (
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 8 }}>
              <i className="bi bi-exclamation-triangle-fill" style={{ color: "#e53e3e", fontSize: "1.1rem" }} />
              <span style={{ fontSize: "0.75rem", color: "#e53e3e", fontWeight: 600, lineHeight: 1.3 }}>
                {errorMessage}
              </span>
            </div>
          ) : (
            <div style={{ display: "flex", alignItems: "baseline", gap: 4, marginBottom: 8 }}>
              <span style={{
                fontSize: "2.2rem", fontWeight: 800, lineHeight: 1,
                color: kpi.color, letterSpacing: "-1px",
              }}>
                {val}
              </span>
              {kpi.unit && (
                <span style={{ fontSize: "0.82rem", color: "var(--sb-muted)", fontWeight: 500 }}>
                  {kpi.unit}
                </span>
              )}
            </div>
          )}

          {/* Formula display */}
          <div style={{
            display: "inline-flex", alignItems: "center", gap: 6,
            padding: "3px 10px", borderRadius: 6,
            background: "var(--sb-light-bg)",
            border: "1px solid var(--sb-border)",
            maxWidth: "100%", overflow: "hidden",
          }}>
            <span style={{ fontSize: "0.65rem", fontWeight: 800, color: kpi.color }}>fx</span>
            <span
              style={{ fontSize: "0.68rem", fontFamily: "monospace", color: "var(--sb-muted)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}
              title={kpi.formula || "No formula"}
            >
              {kpi.formula ? (kpi.formula.length > 24 ? kpi.formula.slice(0, 24) + "…" : kpi.formula) : "—"}
            </span>
          </div>

          {/* Click hint */}
          {!noData && (
            <div style={{ marginTop: 8, fontSize: "0.65rem", color: "var(--sb-muted)", fontStyle: "italic" }}>
              <i className="bi bi-graph-up me-1" style={{ color: kpi.color }} />
              Click icon for trend analysis
            </div>
          )}

          {noData && (
            <div style={{ marginTop: 8 }}>
              <span style={{
                fontSize: "0.65rem", background: "#fee2e2", color: "#b91c1c",
                padding: "2px 8px", borderRadius: 20, fontWeight: 700,
              }}>
                ⚠ No data
              </span>
            </div>
          )}
        </div>
      </div>

      {/* Trend popup */}
      {showTrend && (
        <TrendPopup kpi={kpi} onClose={() => setShowTrend(false)} />
      )}
    </>
  );
};

// ─── KPIManagement ──────────────────────────────────────────────────────────
const KPIManagement = () => {
  const userId = localStorage.getItem("sb_userId");

  const [kpis,        setKpis]        = useState([]);
  const [loadingKpis, setLoadingKpis] = useState(true);
  const [showForm,    setShowForm]    = useState(false);
  const [saving,      setSaving]      = useState(false);
  const [form,        setForm]        = useState({
    name: "", formula: "", unit: "",
    frequency: "5min",           // ← kept as default
    icon: "bi-graph-up", color: "#00c6ae",
  });
  const [errors,      setErrors]      = useState({});
  const [successMsg,  setSuccessMsg]  = useState("");
  const [errMsg,      setErrMsg]      = useState("");
  const [sensors,     setSensors]     = useState([]);
  const [sensorSearch, setSensorSearch] = useState("");
  const [kpiSearch,   setKpiSearch]   = useState("");

  // Fallback live values used when the /latest API has no results
  

  // Per-KPI latest values fetched from /api/KPIs/{kpiId}/latest
  // Shape: { [kpiId]: number | null }
  const [kpiLatestValues, setKpiLatestValues] = useState({});

  // ── Load KPIs ─────────────────────────────────────────────────────────────
  const loadKPIs = async () => {
    if (!userId) { setLoadingKpis(false); return; }
    setLoadingKpis(true);
    try {
      const res  = await fetchKPIs();
      const data = Array.isArray(res.data) ? res.data : res.data?.data ?? [];
      const mapped = data.map((k, i) => ({
        id:        k.kpiId,
        name:      k.kpiName,
        formula:   k.kpiFormula,
        frequency: k.frequency,
        isActive:  k.isActive,
        createdAt: k.createdAt,
        icon:      ICON_MAP[k.kpiName?.toLowerCase()] || "bi-graph-up",
        color:     COLOR_MAP[i % COLOR_MAP.length],
        unit:      "",
        fromApi:   true,
      }));
      setKpis(mapped);
      console.log("KPIs from API:", data.length, data.map(k => ({kpiId: k.kpiId, name: k.kpiName})));
      console.log("Mapped KPIs: ",mapped.length, mapped.map(k => ({id: k.id, name: k.name})));

      // ── Fetch /latest for every KPI in parallel ──────────────────────────
     const settled = await Promise.allSettled(
  mapped.map((k) => fetchKPILatest(k.id).then((r) => ({ id: k.id, data: r.data })))
);
 
const latestEntries = settled.map((result, i) => {
  const kpiId = mapped[i].id;
 
  if (result.status === "rejected") {
    const e = result.reason;
    const isNoResults =
      e?.response?.data?.detail === "No results found for this KPI." ||
      e?.response?.status === 404;
    if (!isNoResults) {
      console.warn(`KPI latest fetch failed for ${kpiId}:`, e?.response?.data || e.message);
    }
    return [kpiId, null];
  }
 
  const raw = result.value.data;
 
  // ── Try every known field shape the backend might return ──
  const candidate =
    raw?.value ??
    raw?.kpiValue ??
    raw?.kpi_value ??
    raw?.latestValue ??
    raw?.latest_value ??
    raw?.result ??
    // If the backend returns an array, grab the first element's value
    (Array.isArray(raw) && raw.length > 0
      ? (raw[0]?.value ?? raw[0]?.kpiValue ?? raw[0])
      : undefined) ??
    // If the whole response is just a plain number
    (typeof raw === "number" ? raw : null);
 
  const num =
    candidate !== null &&
    candidate !== undefined &&
    !isNaN(parseFloat(candidate))
      ? Number(parseFloat(candidate).toFixed(2))
      : null;
 
  // 🔍 Uncomment during debugging to see exactly what the API returns:
  // console.log(`KPI ${kpiId} raw response:`, raw, "→ parsed:", num);
 
  return [kpiId, num];
});
 
setKpiLatestValues(Object.fromEntries(latestEntries));

    } catch (e) {
      setErrMsg(e?.response?.data?.message || "Failed to load KPIs. Please try again.");
      setTimeout(() => setErrMsg(""), 4000);
    } finally { setLoadingKpis(false); }
  };

  useEffect(() => { loadKPIs(); }, [userId]);

  // ── Simulated live values (fallback for formula evaluation) ───────────────
  



  // ── Sensors ───────────────────────────────────────────────────────────────
  useEffect(() => {
    const load = async () => {
      if (!userId) { console.warn("No userId found in localStorage"); return; }
      try {
        const res  = await getSensorByUser(userId);
        const list = Array.isArray(res.data) ? res.data : res.data?.data ?? [];
        setSensors(list.map((s) => ({
          id:       s.sensorId ?? s.id,
          name:     s.sensorName ?? s.name,
          quantity: s.quantity,
          unit:     s.unit,
        })));
      } catch (e) {
        console.error("Sensor API failed:", e?.response?.status, e?.response?.data || e.message);
      }
    };
    load();
  }, [userId]);

  // ── Insert into formula ────────────────────────────────────────────────────
  const insertToFormula = (text) => setForm((f) => ({ ...f, formula: f.formula + text }));
  const insertFunction  = (fn)   => setForm((f) => ({ ...f, formula: f.formula + `${fn}(` }));

  // ── Add KPI ───────────────────────────────────────────────────────────────
  const handleAddKpi = async () => {
    const errs = {};
    if (!form.name.trim())    errs.name    = "KPI name is required.";
    if (!form.formula.trim()) errs.formula = "Formula is required.";
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setSaving(true);
    try {
      await createKPI(form);
      setForm({ name: "", formula: "", unit: "", frequency: "5min", icon: "bi-graph-up", color: "#00c6ae" });
      setShowForm(false); setSensorSearch(""); setErrors({});
      setSuccessMsg(`KPI "${form.name}" created successfully!`);
      setTimeout(() => setSuccessMsg(""), 3500);
      await loadKPIs();
    } catch (e) {
      setErrMsg(e?.response?.data?.message || "Failed to create KPI. Please check your inputs and try again.");
      setTimeout(() => setErrMsg(""), 4000);
    } finally { setSaving(false); }
  };

  // ── Enrich KPIs: prefer /latest value, fall back to formula eval ──────────
  const enrichedKpis = kpis.map((k) => {
    const latestFromApi = kpiLatestValues[k.id]; // number | null | undefined
   const liveVal =
  latestFromApi !== null && latestFromApi !== undefined
    ? String(latestFromApi)
    : null;
    return { ...k, _liveVal: liveVal };
  });

  const filteredKpis    = enrichedKpis.filter((k) =>
    k.name.toLowerCase().includes(kpiSearch.toLowerCase())
  );
  const filteredSensors = sensors.filter((s) =>
    s.name?.toLowerCase().includes(sensorSearch.toLowerCase())
  );

  const preview          =  null;
  const formulaIsInvalid = false;

  return (
    <div>
      <style>{`
        @keyframes pulseDot {
          0%,100% { opacity:1; transform:scale(1); }
          50%      { opacity:0.4; transform:scale(0.7); }
        }
        .op-btn {
          width:40px; height:36px; border:1px solid var(--sb-border);
          border-radius:8px; background:var(--sb-light-bg); color:var(--sb-text);
          font-weight:700; font-size:1rem; cursor:pointer;
          display:inline-flex; align-items:center; justify-content:center;
          transition:background 0.15s, border-color 0.15s;
        }
        .op-btn:hover { background:var(--sb-accent); color:#fff; border-color:var(--sb-accent); }
        .fn-btn {
          padding:4px 12px; border-radius:20px; border:1px solid var(--sb-border);
          background:var(--sb-light-bg); color:var(--sb-accent);
          font-size:0.78rem; font-weight:700; cursor:pointer; font-family:monospace;
          transition:background 0.15s;
        }
        .fn-btn:hover { background:var(--sb-accent); color:#fff; }
        .sensor-chip {
          display:inline-flex; align-items:center; gap:5px;
          padding:4px 12px; border-radius:20px;
          background:var(--sb-light-bg); border:1px solid var(--sb-border);
          color:var(--sb-text); font-size:0.78rem; font-weight:600;
          cursor:pointer; transition:all 0.15s; white-space:nowrap;
        }
        .sensor-chip:hover { background:var(--sb-accent); color:#fff; border-color:var(--sb-accent); }
        .fx-bar {
          display:flex; align-items:center; background:var(--sb-light-bg);
          border:1.5px solid var(--sb-border); border-radius:10px; padding:8px 14px;
          transition:border-color 0.2s;
        }
        .fx-bar:focus-within { border-color:var(--sb-accent); background:var(--sb-white); }
        .fx-bar input { flex:1; background:none; border:none; outline:none; color:var(--sb-text); font-family:monospace; font-size:0.9rem; }
        .modal-overlay {
          position:fixed; inset:0; background:rgba(0,0,0,0.45);
          display:flex; align-items:center; justify-content:center;
          z-index:1050; padding:16px;
        }
        .modal-box {
          width:100%; max-width:760px; background:var(--sb-white);
          border-radius:20px; box-shadow:0 24px 60px rgba(0,0,0,0.15); overflow:hidden;
        }
        .modal-header  { padding:20px 28px 16px; border-bottom:1px solid var(--sb-border); display:flex; align-items:center; justify-content:space-between; }
        .modal-body    { padding:20px 28px; display:grid; grid-template-columns:1fr 1fr; gap:20px; }
        .modal-footer  { padding:16px 28px; border-top:1px solid var(--sb-border); display:flex; justify-content:flex-end; gap:10px; }
        .field-label   { font-size:0.7rem; font-weight:700; letter-spacing:0.8px; text-transform:uppercase; color:var(--sb-muted); margin-bottom:5px; display:block; }
        .field-input   { width:100%; background:var(--sb-light-bg); border:1px solid var(--sb-border); border-radius:8px; padding:8px 12px; color:var(--sb-text); font-size:0.87rem; outline:none; font-family:inherit; transition:border-color 0.2s; }
        .field-input:focus { border-color:var(--sb-accent); background:var(--sb-white); }
        .field-input.err   { border-color:#e53e3e; }
        .field-select  { width:100%; background:var(--sb-light-bg); border:1px solid var(--sb-border); border-radius:8px; padding:8px 12px; color:var(--sb-text); font-size:0.87rem; outline:none; font-family:inherit; transition:border-color 0.2s; cursor:pointer; }
        .field-select:focus { border-color:var(--sb-accent); background:var(--sb-white); }
        .kpi-search-input { background:var(--sb-light-bg); border:1px solid var(--sb-border); border-radius:50px; padding:8px 16px 8px 36px; color:var(--sb-text); font-size:0.85rem; outline:none; width:220px; transition:border-color 0.2s; }
        .kpi-search-input:focus { border-color:var(--sb-accent); background:var(--sb-white); }

        /* Formula box */
        .formula-box {
          background: var(--sb-light-bg);
          border-radius: 10px;
          padding: 10px 14px;
          min-height: 48px;
          font-family: monospace;
          font-size: 0.9rem;
          color: var(--sb-text);
          word-break: break-all;
          display: flex;
          align-items: center;
          gap: 8px;
          flex-wrap: wrap;
          cursor: text;
          transition: border-color 0.2s, background 0.2s;
          position: relative;
        }
        .formula-box.valid   { border: 1.5px solid var(--sb-accent); }
        .formula-box.invalid { border: 1.5px solid #e53e3e; background: rgba(229,62,62,0.04); }
        .formula-box.empty   { border: 1.5px solid var(--sb-border); }
        .formula-fx-tag {
          font-size: 0.72rem; font-weight: 800;
          padding: 2px 7px; border-radius: 5px;
          background: var(--sb-accent); color: #fff;
          flex-shrink: 0;
        }
        .formula-text { flex: 1; }
        .formula-clear-btn {
          position: absolute; top: 6px; right: 8px;
          background: none; border: none;
          color: var(--sb-muted); cursor: pointer; font-size: 14px;
          line-height: 1; padding: 2px 4px; border-radius: 4px;
          transition: background 0.1s;
        }
        .formula-clear-btn:hover { background: var(--sb-border); }
      `}</style>

      {/* Page Header */}
      <div className="sb-page-header px-4 py-3 mb-4">
        <div className="d-flex align-items-center justify-content-between flex-wrap gap-2">
          <div>
            <h5 className="sb-header-title mb-1">
              <i className="bi bi-graph-up-arrow me-2 sb-accent" />KPI Management
            </h5>
            <p className="sb-header-subtitle mb-0">Monitor and manage your Key Performance Indicators.</p>
          </div>
          <div className="d-flex align-items-center gap-2 flex-wrap">
            <div style={{ position: "relative" }}>
              <i className="bi bi-search" style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--sb-muted)", fontSize: "0.85rem" }} />
              <input
                type="text"
                className="kpi-search-input"
                placeholder="Search KPIs…"
                value={kpiSearch}
                onChange={(e) => setKpiSearch(e.target.value)}
              />
            </div>

            <button
              className="btn sb-connect-btn d-flex align-items-center gap-2"
              style={{ borderRadius: "50px", padding: "8px 22px", fontWeight: 600 }}
              onClick={() => setShowForm(true)}
            >
              <i className="bi bi-plus-circle-fill" />Add KPI
            </button>
          </div>
        </div>
      </div>

      {/* Toast notifications */}
      {(successMsg || errMsg) && (
        <div className="position-fixed top-0 end-0 m-4" style={{ zIndex: 9999 }}>
          {successMsg && (
            <div className="alert alert-success shadow border-0 d-flex align-items-center gap-2">
              <i className="bi bi-check-circle-fill" />{successMsg}
            </div>
          )}
          {errMsg && (
            <div className="alert alert-danger shadow border-0 d-flex align-items-center gap-2">
              <i className="bi bi-exclamation-circle-fill" />{errMsg}
            </div>
          )}
        </div>
      )}

      {/* KPI Cards */}
      <div className="container-fluid px-4">
        {loadingKpis ? (
          <div className="text-center py-5">
            <div className="spinner-border" style={{ color: "var(--sb-accent)" }} />
            <p className="mt-2 text-muted small">Loading KPIs…</p>
          </div>
        ) : kpis.length === 0 ? (
          <div className="text-center py-5" style={{ color: "var(--sb-muted)" }}>
            <i className="bi bi-graph-up" style={{ fontSize: "2.5rem" }} />
            <p className="mt-2">No KPIs configured yet. Click <strong>Add KPI</strong> to create your first one.</p>
          </div>
        ) : filteredKpis.length === 0 ? (
          <div className="text-center py-5" style={{ color: "var(--sb-muted)" }}>
            <i className="bi bi-search" style={{ fontSize: "2rem" }} />
            <p className="mt-2">No KPIs match <strong>"{kpiSearch}"</strong>. Try a different search term.</p>
          </div>
        ) : (
          <div className="row g-3">
            {filteredKpis.map((kpi) => (
              <div className="col-12 col-sm-6 col-lg-4 col-xl-3" key={kpi.id}>
                <KPICard kpi={kpi} />
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Add KPI Modal */}
      {showForm && (
        <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && setShowForm(false)}>
          <div className="modal-box">
            <div className="modal-header">
              <div>
                <h5 style={{ margin: 0, fontWeight: 700, color: "var(--sb-text)", fontSize: "1.05rem" }}>
                  <i className="bi bi-function me-2" style={{ color: "var(--sb-accent)" }} />New KPI Formula
                </h5>
                <p style={{ margin: 0, fontSize: "0.75rem", color: "var(--sb-muted)", marginTop: 2 }}>
                  Build a formula using operators, functions and sensor variables
                </p>
              </div>
              <button className="btn-close" onClick={() => { setShowForm(false); setErrors({}); }} />
            </div>

            <div className="modal-body">
              {/* LEFT COL */}
              <div>
                {/* Name + Unit */}
                <div className="d-flex gap-2 mb-3">
                  <div style={{ flex: 2 }}>
                    <label className="field-label">KPI Name *</label>
                    <input
                      className={`field-input ${errors.name ? "err" : ""}`}
                      placeholder="e.g. Machine Efficiency"
                      value={form.name}
                      onChange={(e) => { setForm((f) => ({ ...f, name: e.target.value })); setErrors((v) => ({ ...v, name: "" })); }}
                    />
                    {errors.name && <p style={{ fontSize: "0.68rem", color: "#e53e3e", margin: "3px 0 0" }}>{errors.name}</p>}
                  </div>
                  <div style={{ flex: 1 }}>
                    <label className="field-label">Unit</label>
                    <input className="field-input" placeholder="%, hrs" value={form.unit}
                      onChange={(e) => setForm((f) => ({ ...f, unit: e.target.value }))} />
                  </div>
                </div>

                {/* ── Frequency (NEW — inside form) ── */}
                <div className="mb-3">
                  <label className="field-label">Frequency</label>
                  <select
                    className="field-select"
                    value={form.frequency}
                    onChange={(e) => setForm((f) => ({ ...f, frequency: e.target.value }))}
                  >
                    {FREQUENCIES.map((freq) => (
                      <option key={freq} value={freq}>{freq}</option>
                    ))}
                  </select>
                </div>

                {/* Operators */}
                <label className="field-label">Operators</label>
                <div className="d-flex gap-1 mb-2 flex-wrap">
                  {OPERATORS.map((op) => (
                    <button key={op.label} type="button" className="op-btn"
                      onClick={() => insertToFormula(op.val)}>{op.label}</button>
                  ))}
                  {FX_FUNCS.map((fn) => (
                    <button key={fn} type="button" className="fn-btn"
                      onClick={() => insertFunction(fn)}>{fn}()</button>
                  ))}
                  <button type="button" className="op-btn" title="Close function"
                    onClick={() => insertToFormula(")")}>
                    <span style={{ fontSize: "0.75rem", fontWeight: 800 }}>fx)</span>
                  </button>
                </div>

                {/* Formula display box */}
                <label className="field-label mt-2">Formula *</label>
                <div className={`formula-box ${!form.formula.trim() ? "empty" : formulaIsInvalid ? "invalid" : "valid"}`}>
                  <span className="formula-fx-tag">fx</span>
                  <span className="formula-text">
                    {form.formula || (
                      <span style={{ color: "var(--sb-muted)", fontStyle: "italic", fontSize: "0.82rem" }}>
                        Click operators &amp; sensors to build formula…
                      </span>
                    )}
                  </span>
                  {form.formula && (
                    <button
                      type="button"
                      className="formula-clear-btn"
                      onClick={() => { setForm((f) => ({ ...f, formula: "" })); setErrors((e) => ({ ...e, formula: "" })); }}
                      title="Clear formula"
                    >
                      <i className="bi bi-x-circle" />
                    </button>
                  )}
                </div>
                {errors.formula && (
                  <p style={{ fontSize: "0.68rem", color: "#e53e3e", margin: "3px 0 0" }}>
                    <i className="bi bi-exclamation-triangle me-1" />{errors.formula}
                  </p>
                )}

                {form.formula.trim() && (
<div style={{

    marginTop: 6,

    padding: "7px 12px",

    background: "rgba(0,198,174,0.08)",

    borderRadius: 8,

    fontSize: "0.8rem",

    border: "1px solid #00c6ae40",

    display: "flex",

    alignItems: "center",

    gap: 6,

  }}>
<i className="bi bi-info-circle" style={{ color: "#00c6ae" }} />
<span>

      KPI will be calculated from real sensor data after creation
</span>
</div>

)}
 

                <div className="d-flex gap-2 mt-3">
                  <div style={{ flex: 1 }}>
                    <label className="field-label">Color</label>
                    <input type="color" className="field-input p-1" value={form.color}
                      onChange={(e) => setForm((f) => ({ ...f, color: e.target.value }))} style={{ height: "38px" }} />
                  </div>
                  <div style={{ flex: 2 }}>
                    <label className="field-label">Icon class</label>
                    <input className="field-input" placeholder="bi-graph-up" value={form.icon}
                      onChange={(e) => setForm((f) => ({ ...f, icon: e.target.value }))} />
                  </div>
                </div>
              </div>

              {/* RIGHT COL — sensors */}
              <div style={{ borderLeft: "1px solid var(--sb-border)", paddingLeft: 20 }}>
                <label className="field-label">Sensor Variables</label>
                <p style={{ fontSize: "0.73rem", color: "var(--sb-muted)", marginBottom: 10 }}>
                  Click a sensor to insert its variable into the formula.
                  <br />
                  <span style={{ color: "var(--sb-accent)", fontWeight: 600 }}>Tip:</span> Click a function first, then a sensor, then close with <code>)</code>
                </p>
                <div className="fx-bar mb-3" style={{ padding: "6px 12px" }}>
                  <i className="bi bi-search me-2" style={{ color: "var(--sb-muted)", fontSize: "0.8rem" }} />
                  <input
                    placeholder="Search sensors…"
                    value={sensorSearch}
                    onChange={(e) => setSensorSearch(e.target.value)}
                    style={{ flex: 1, background: "none", border: "none", outline: "none", fontSize: "0.83rem", color: "var(--sb-text)" }}
                  />
                </div>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6, maxHeight: "240px", overflowY: "auto" }}>
                  {filteredSensors.length === 0 ? (
                    <p style={{ fontSize: "0.78rem", color: "var(--sb-muted)", width: "100%", textAlign: "center", paddingTop: 20 }}>
                      <i className="bi bi-broadcast me-1" />
                      {sensors.length === 0
                        ? "No sensors connected. Add sensors in the Sensors module."
                        : "No sensors match your search."}
                    </p>
                  ) : filteredSensors.map((s) => (
                    <button key={s.id} type="button" className="sensor-chip"
                      onClick={() => insertToFormula(`sensor_${s.id}`)}>
                      <i className="bi bi-broadcast" style={{ fontSize: "0.65rem", color: "var(--sb-accent)" }} />
                      sensor_{s.id}
                      {s.name && <span style={{ opacity: 0.6, fontSize: "0.7rem" }}>· {s.name}</span>}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="modal-footer">
              <button
                style={{ padding: "8px 22px", borderRadius: "8px", border: "1.5px solid var(--sb-border)", background: "none", color: "var(--sb-text)", fontWeight: 600, cursor: "pointer" }}
                onClick={() => { setShowForm(false); setErrors({}); }}
              >
                Cancel
              </button>
              <button
                className="btn sb-connect-btn"
                style={{ borderRadius: "8px", padding: "8px 24px", fontWeight: 600 }}
                onClick={handleAddKpi}
                disabled={saving}
              >
                {saving
                  ? <><span className="spinner-border spinner-border-sm me-2" />Saving…</>
                  : <><i className="bi bi-plus-circle me-2" />Add KPI</>
                }
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default KPIManagement;
